<template><div class="page home"><section class="shop"><div class="logo">K</div><div><h1>Koshop 卖家中心</h1><p>Dujiao-Next 实时经营概览</p></div></section><p v-if="error" class="error">{{error}} <button @click="load">重试</button></p><section v-else class="core"><article><span>今日支付金额</span><b>¥{{d.todayPaidAmount||0}}</b></article><article><span>今日订单</span><b>{{d.todayOrders||0}}</b></article><article><span>低库存</span><b>{{d.lowStock||0}}</b></article></section><section class="todos"><button v-for="x in [['待付款',d.pendingPayment],['待发货',d.pendingDelivery],['待售后',d.afterSale],['访客',d.todayVisitors]]"><b>{{x[1]||0}}</b><span>{{x[0]}}</span></button></section><section class="card"><h2>快捷入口</h2><div class="entry"><button v-for="x in entries" @click="navigate(x[1])"><component :is="x[2]"/>{{x[0]}}</button></div></section></div></template><script setup lang="ts">import{onMounted,ref}from'vue';import{Package,ClipboardList,Wallet,MessageCircle,Settings}from'lucide-vue-next';import{navigate}from'../router';const d=ref<any>({}),error=ref(''),entries:any[]=[['商品','/products',Package],['订单','/orders',ClipboardList],['财务','/finance',Wallet],['消息','/messages',MessageCircle],['设置','/settings',Settings]];async function load(){try{const r=await fetch('/api/koshop-seller/dashboard'),j=await r.json();if(!r.ok||!j.ok)throw Error(j.message);d.value=j.data;error.value=''}catch(e:any){error.value=e.message||'Dujiao Admin 接口暂不可用'}}onMounted(load)</script>
